                        @input=\"search\"\r\n                    >\r\n                    </el-input>\r\n                </div>\r\n                <!-- <div class=\"col-md-4\">\r\n                    <el-button\r\n                        :type=\"showSelecteds ? 'primary' : 'danger'\"\r\n                        @click=\"showSelected\"\r\n                    >\r\n                        {{ showSelecteds ? \"Ocultar\" : \"Ver seleccionados\" }}\r\n                    </el-button>\r\n                </div> -->\r\n            </div>\r\n            <table v-loading=\"loading\" class=\"table\">\r\n                <thead>\r\n                    <tr>\r\n                        <th>#</th>\r\n                        <th>Serie</th>\r\n                        <th>Fecha</th>\r\n                        <th>Lote</th>\r\n                        <th>Seleccionar</th>\r\n                    </tr>\r\n                </thead>\r\n                <tbody>\r\n                    <tr v-for=\"(serie, idx) in series\" :key=\"serie.id\">\r\n                        <td>{{ customIndex(idx) }}</td>\r\n                        <td>{{ serie.series }}</td>\r\n                        <td>{{ serie.date }}</td>\r\n                        <td>{{ serie.lote }}</td>\r\n                        <td>\r\n                            <el-checkbox\r\n                                :disabled=\"serie.disabled\"\r\n                                v-model=\"serie.selected\"\r\n                                @change=\"saveSerie(serie)\"\r\n                            >\r\n                            </el-checkbox>\r\n                        </td>\r\n                    </tr>\r\n                </tbody>\r\n            </table>\r\n            <el-pagination\r\n                @current-change=\"getSeries\"\r\n                layout=\"total, prev, pager, next\"\r\n                :total=\"pagination.total\"\r\n                :current-page.sync=\"pagination.current_page\"\r\n                :page-size=\"pagination.per_page\"\r\n            >\r\n            </el-pagination>\r\n            <span slot=\"footer\" class=\"dialog-footer\">\r\n                <el-button @click=\"close\">Cerrar</el-button>\r\n                <el-button type=\"primary\" @click=\"save\">Guardar</el-button>\r\n            </span>\r\n        </div>\r\n    </el-dialog>\r\n</template>\r\n\r\n<script>\r\nimport queryString from \"query-string\";\r\nexport default {\r\n    props: [\"showDialog\", \"limitQty\", \"item\", \"idx\", \"seriesSelected\"],\r\n    data() {\r\n        return {\r\n            loading: false,\r\n            series: [],\r\n            pagination: {},\r\n            inputSearch: null,\r\n            timer: null,\r\n            showSelecteds: false\r\n        };\r\n    },\r\n    methods: {\r\n        checkSeries() {\r\n            for (let i = 0; i < this.series.length; i++) {\r\n                let serie = this.seriesSelected.find(\r\n                    s => s.id == this.series[i].id\r\n                );\r\n                if (serie) {\r\n                    this.series[i].selected = true;\r\n                    this.series[i].disabled = serie.disabled;\r\n                }\r\n\r\n                // if (this.seriesSelected.some(s => s.id == this.series[i].id)) {\r\n                // }\r\n            }\r\n        },\r\n        showSelected() {\r\n            this.showSelecteds = !this.showSelecteds;\r\n        },\r\n        customIndex(index) {\r\n            return (\r\n                this.pagination.per_page * (this.pagination.current_page - 1) +\r\n                index +\r\n                1\r\n            );\r\n        },\r\n        saveSerie(serie) {\r\n            let series = [\r\n                ...this.seriesSelected.filter(\r\n                    s => s.disabled != null && s.disabled == false\r\n                )\r\n            ];\r\n            if (serie.selected) {\r\n                serie.disabled = false;\r\n                series = [...series, serie];\r\n            } else {\r\n                series = series.filter(s => s.id != serie.id);\r\n            }\r\n            this.$forceUpdate();\r\n            this.$emit(\"update:seriesSelected\", series);\r\n        },\r\n        save() {\r\n            this.$emit(\"updateSeries\", this.idx, this.seriesSelected);\r\n            this.close();\r\n        },\r\n        getQueryParameters() {\r\n            return queryString.stringify({\r\n                page: this.pagination.current_page,\r\n                item_id: this.item.id,\r\n                description: this.inputSearch\r\n            });\r\n        },\r\n        open() {\r\n            console.log(this.limitQty);\r\n\r\n            if (this.item) {\r\n                this.getSeries();\r\n            }\r\n        },\r\n        search() {\r\n            if (this.timer) {\r\n                clearTimeout(this.timer);\r\n            }\r\n            this.timer = setTimeout(async () => {\r\n                await this.getSeries();\r\n            }, 350);\r\n        },\r\n        close() {\r\n            this.inputSearch = null;\r\n            this.pagination = {};\r\n            this.series = [];\r\n            this.$emit(\"update:showDialog\", false);\r\n        },\r\n        async getSeries() {\r\n            try {\r\n                this.loading = true;\r\n                const response = await this.$http(\r\n                    `/lotitem/series-by-item?${this.getQueryParameters()}`\r\n                );\r\n                let { data, meta } = response.data;\r\n                this.series = data;\r\n                this.checkSeries();\r\n                this.pagination = meta;\r\n                this.pagination.per_page = parseInt(meta.per_page);\r\n            } catch (e) {\r\n                console.log(e);\r\n            } finally {\r\n                this.loading = false;\r\n            }\r\n        }\r\n    }\r\n};\r\n</script>\r\n\n\n\n// WEBPACK FOOTER //\n// modules/Internet/Resources/assets/js/view/pos/partials/show_series_pro